@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam linetype ortho

interface HouseBuilder {
  +void buildBasic();
  +void buildBody();
  +void buildRoof();
  +House finish();
}

class CommonHouseBuilder {
  -House house;
  +void buildBasic();
  +void buildBody();
  +void buildRoof();
  +House finish();
}

class LuxuryHouseBuilder {
  -House house;
  +void buildBasic();
  +void buildBody();
  +void buildRoof();
  +House finish();
}

class Decorate {
  -HouseBuilder houseBuilder;
  +House construct();
}

class House {
  -String type;
  -boolean base;
  -boolean body;
  -boolean roof;
}

class Client

CommonHouseBuilder ..|> HouseBuilder
LuxuryHouseBuilder ..|> HouseBuilder

Decorate --> HouseBuilder

CommonHouseBuilder o--> House
LuxuryHouseBuilder o--> House

Client --> Decorate

note top of Decorate
具体建造对象
end note

note left of House
具体产品类
end note
@enduml
